import boto3
import json
import os

# Initialize SQS client
sqs = boto3.client('sqs', region_name='your-region')

# Replace with your SQS queue URL
queue_url = 'https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name'

def send_message(user_data):
    # Ensure PII data is handled securely
    message_body = json.dumps(user_data)
    
    response = sqs.send_message(
        QueueUrl=queue_url,
        MessageBody=message_body
    )
    
    return response

